(function(g){'use strict';class P{constructor(){this.pyodide=null;this.ready=false;this.q=[];this.c=new Map();this.components=new Map();this.init()}async init(){if(this.ready)return;this.showLoader();try{await this.loadPyodide();await this.initPython();this.ready=true;this.hideLoader();this.processDOM();this.observeDOM();console.log('PYTML Ready')}catch(e){this.showError(e.message)}}async loadPyodide(){const c=['https://cdn.jsdelivr.net/pyodide/v0.24.1/full/pyodide.js','https://unpkg.com/pyodide@0.24.1/pyodide.js'];for(const u of c){try{if(typeof loadPyodide==='undefined'){await this.loadScript(u)}break}catch(e){}}this.pyodide=await loadPyodide({indexURL:'https://cdn.jsdelivr.net/pyodide/v0.24.1/full/',fullStdLib:false})}async initPython(){await this.pyodide.runPythonAsync(`import sys,io,json,re
class F:
    __slots__=['b']
    def __init__(s):s.b=[]
    def write(s,t):s.b.append(str(t))
    def get(s):return''.join(s.b)
    def clear(s):s.b=[]
class R:
    __slots__=['o','c','g']
    def __init__(s):s.o=F();s.c={};s.g={}
    def e(s,c,i):
        s.o.clear()
        o=sys.stdout
        sys.stdout=s.o
        try:
            if i:
                for k,v in i.items():s.g[k]=v
            exec(c,s.g)
            r=s.o.get()
            sys.stdout=o
            return r
        except Exception as ex:
            sys.stdout=o
            raise ex
r=R()
def q(c,i):return r.e(c,i)`)}async run(c,i={}){if(!this.ready)await this.wait();const k=`${c}_${JSON.stringify(i)}`;if(this.c.has(k))return this.c.get(k);try{const r=await this.pyodide.runPythonAsync(`q(${JSON.stringify(c)},${JSON.stringify(i)})`);setTimeout(()=>this.c.delete(k),1e3);this.c.set(k,r);return r}catch(e){return`Error: ${e.message}`}}processDOM(){document.querySelectorAll('[data-python-text]').forEach(async e=>{const c=e.getAttribute('data-python-text');const r=await this.run(`result=${c}\nprint(result)`);if(e)e.textContent=r});document.querySelectorAll('[data-python-html]').forEach(async e=>{const c=e.getAttribute('data-python-html');const r=await this.run(`result=${c}\nprint(result)`);if(e)e.innerHTML=r});document.querySelectorAll('[data-python]').forEach(e=>{const c=e.getAttribute('data-python');const t=e.getAttribute('data-event')||'click';const s=e.getAttribute('data-target');const d=parseInt(e.getAttribute('data-debounce')||'300');let to=null;const h=async()=>{if(to)return;if(e.getAttribute('data-loader')!=='false')this.showButtonLoader(e);to=setTimeout(async()=>{try{const i=this.collectInputs(e);const r=await this.run(c,i);if(s){const tg=document.querySelector(s);if(tg)tg.innerHTML=r.replace(/\n/g,'<br>')}if(e.getAttribute('data-output-self')==='true')e.innerHTML=r}catch(err){if(s){const tg=document.querySelector(s);if(tg)tg.innerHTML=`<span style="color:#dc3545">${err.message}</span>`}}finally{if(e.getAttribute('data-loader')!=='false')this.hideButtonLoader(e);to=null}},d)};e.removeEventListener(t,h);e.addEventListener(t,h)})}collectInputs(e){const i={};const f=e.closest('[data-python-form]');if(f){f.querySelectorAll('input, select, textarea').forEach(inp=>{if(inp.name){let v=inp.value;if(inp.type==='number')v=parseFloat(v);if(inp.type==='checkbox')v=inp.checked;if(inp.type==='radio'&&inp.checked)v=inp.value;i[inp.name]=v}})}return i}observeDOM(){new MutationObserver(()=>this.processDOM()).observe(document.body,{childList:true,subtree:true})}showLoader(){let l=document.getElementById('pytml-loader');if(!l){l=document.createElement('div');l.id='pytml-loader';l.innerHTML='<div style="position:fixed;bottom:20px;right:20px;background:#007acc;color:white;padding:10px 15px;border-radius:8px;font-family:monospace;font-size:12px;z-index:10000">🐍 PYTML: Loading...</div>';document.body.appendChild(l)}}hideLoader(){const l=document.getElementById('pytml-loader');if(l)l.remove()}showButtonLoader(b){const t=b.innerHTML;b.setAttribute('data-original',t);b.innerHTML='⏳ Processing...';b.disabled=true}hideButtonLoader(b){const o=b.getAttribute('data-original');if(o)b.innerHTML=o;b.disabled=false}showError(m){const e=document.createElement('div');e.style.cssText='position:fixed;top:20px;right:20px;background:#dc3545;color:white;padding:10px;border-radius:5px;z-index:10000';e.textContent=`PYTML Error: ${m}`;document.body.appendChild(e);setTimeout(()=>e.remove(),5e3)}loadScript(s){return new Promise((r,j)=>{const t=document.createElement('script');t.src=s;t.onload=r;t.onerror=j;document.head.appendChild(t)})}async wait(){if(this.ready)return;return new Promise(r=>this.q.push(r))}getStatus(){return{ready:this.ready,version:'3.2.0'}}}const p=new P;g.pytml=p;if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',()=>p.processDOM())}else{p.processDOM()}})(window);
